## 🛠️ 快速修复脚本

```bash
#!/bin/bash
# security-fix.sh - 快速安全修复脚本

set -e

echo "🔒 开始安全修复..."

# 1. 创建 .env.example
echo "📝 创建 .env.example..."
cat > .env.example << 'EOF'
# 智谱 GLM API 配置
ANTHROPIC_AUTH_TOKEN=your_api_key_here
ANTHROPIC_BASE_URL=https://open.bigmodel.cn/api/anthropic
API_TIMEOUT_MS=3000000
CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC=1

# JWT 密钥（用于 WebSocket 认证）
JWT_SECRET=your_jwt_secret_here_generate_with_openssl_rand

# Dashboard 配置
DASHBOARD_PORT=3000
DASHBOARD_HOST=localhost
EOF

# 2. 删除敏感文件
echo "🗑️ 删除敏感测试文件..."
rm -f trace-sdk.mjs test-skip-perms.mjs send-feishu-notify.mjs get-user-id.mjs

# 3. 生成 JWT 密钥
echo "🔐 生成 JWT 密钥..."
JWT_SECRET=$(openssl rand -base64 64)
echo "JWT_SECRET=${JWT_SECRET}" >> .env.local

# 4. 运行 npm audit
echo "🔍 运行安全审计..."
npm audit || true

# 5. 创建 .github/workflows/security.yml
echo "📦 创建 CI/CD 安全工作流..."
mkdir -p .github/workflows
cat > .github/workflows/security.yml << 'EOF'
name: Security Audit

on:
  push:
    branches: [ main, develop ]
  pull_request:
    branches: [ main ]
  schedule:
    - cron: '0 0 * * 0'  # 每周日运行

jobs:
  audit:
    runs-on: ubuntu-latest

    steps:
      - uses: actions/checkout@v3

      - name: Setup Node.js
        uses: actions/setup-node@v3
        with:
          node-version: '20'
          cache: 'npm'

      - name: Install dependencies
        run: npm ci

      - name: Run npm audit
        run: npm audit --audit-level=moderate

      - name: Run Snyk security scan
        uses: snyk/actions/node@master
        continue-on-error: true
        env:
          SNYK_TOKEN: ${{ secrets.SNYK_TOKEN }}
        with:
          args: --severity-threshold=high
