```typescript
/**
 * 安全的命令执行工具
 * 防止命令注入和其他安全问题
 */

import { execFileSync, ExecFileSyncOptions } from 'child_process';

/**
 * 消毒 Git 提交消息
 * 移除可能导致命令注入的字符
 */
export function sanitizeCommitMessage(message: string): string {
  return message
    .replace(/[\n\r\t]/g, ' ')      // 替换换行符
    .replace(/[;&|`$()]/g, '')       // 移除 shell 元字符
    .replace(/\s+/g, ' ')            // 压缩空格
    .trim()
    .substring(0, 72);               // Git 限制
}

/**
 * 安全地执行 Git 命令
 * 使用参数化方式，避免 shell 注入
 */
export function safeExecGit(
  args: string[],
  cwd: string,
  options: { timeout?: number } = {}
): string {
  const opts: ExecFileSyncOptions = {
    cwd,
    encoding: 'utf-8',
    timeout: options.timeout || 30000,      // 默认 30s 超时
    maxBuffer: 10 * 1024 * 1024            // 10MB 缓冲区
  };

  try {
    return execFileSync('git', args, opts);
  } catch (error: any) {
    // 详细的错误处理
    if (error.killed) {
      throw new Error(`Git 命令执行超时: git ${args.join(' ')}`);
    }
    if (error.status !== 0) {
      throw new Error(`Git 命令失败 (${error.status}): git ${args.join(' ')}\n${error.stderr || ''}`);
    }
    throw error;
  }
}

/**
 * 安全地执行 Git 提交
 */
export function safeGitCommit(
  message: string,
  cwd: string
): { commitId: string; success: boolean } {
  // 1. 消毒消息
  const safeMessage = sanitizeCommitMessage(message);

  // 2. 执行 git add
  safeExecGit(['add', '.'], cwd);

  // 3. 执行 git commit（使用参数化）
  safeExecGit(['commit', '-m', safeMessage], cwd);

  // 4. 获取新提交 ID
  const commitId = safeExecGit(['rev-parse', '--short', 'HEAD'], cwd).trim();

  return { commitId, success: true };
}
```

