#### 2. 实现 JWT 认证中间件（0.5 天）

```typescript
// src/dashboard/middleware/auth.ts
import { FastifyRequest, FastifyReply } from 'fastify';
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key';

export interface AuthenticatedRequest extends FastifyRequest {
  userId?: string;
  role?: 'admin' | 'user' | 'readonly';
}

export async function authenticateToken(
  request: AuthenticatedRequest,
  reply: FastifyReply
) {
  const authHeader = request.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer TOKEN

  if (!token) {
    return reply.code(401).send({
      success: false,
      error: { message: 'Access token required', code: 'UNAUTHORIZED' }
    });
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET) as any;
    request.userId = decoded.userId;
    request.role = decoded.role;
  } catch (err) {
    return reply.code(403).send({
      success: false,
      error: { message: 'Invalid or expired token', code: 'FORBIDDEN' }
    });
  }
}

export function requireRole(allowedRoles: string[]) {
  return async (request: AuthenticatedRequest, reply: FastifyReply) => {
    if (!request.role || !allowedRoles.includes(request.role)) {
      return reply.code(403).send({
        success: false,
        error: { message: 'Insufficient permissions', code: 'FORBIDDEN' }
      });
    }
  };
}
```

